import { useState } from 'react';

export default function useForm(steps) {
    
    const [currentStep, setCurrentStep] = useState(0);

    function changeStep(i, e) {
        e.preventDefault();

        if(i < 0 || i >= steps.length) return

        setCurrentStep(i)
    }

    return {
        currentStep,
        currentComponent: steps[currentStep],
        changeStep
    };
};
